import classNames from 'classnames';
import * as React from 'react';
import * as ReactDOM from 'react-dom';
import { useTranslation } from 'react-i18next';
import {
  ActionGroup,
  Button,
  Content,
  ContentVariants,
  Modal,
} from '@patternfly/react-core';
import { ButtonBar } from '../common/button-bar';
import CloseButton from './CloseButton';

export const ModalTitle: React.FC<ModalTitleProps> = ({
  children,
  className = 'modal-header',
  close,
}) => (
  <div className={className}>
    <Content>
      <Content component={ContentVariants.h1} data-test-id="modal-title">
        {children}
        {close && (
          <CloseButton
            onClick={(e) => {
              e.stopPropagation();
              close(e);
            }}
            additionalClassName="co-close-button--float-right"
          />
        )}
      </Content>
    </Content>
  </div>
);

export const ModalBody: React.FC<ModalBodyProps> = ({
  children,
  className = 'modal-body-content',
}) => (
  <div className="modal-body">
    <div className={className}>{children}</div>
  </div>
);

export const ModalFooter: React.FC<ModalFooterProps> = ({
  message,
  errorMessage,
  inProgress,
  children,
  className = 'modal-footer',
}) => {
  return (
    <ButtonBar
      className={className}
      errorMessage={errorMessage}
      infoMessage={message}
      inProgress={inProgress}
    >
      {children}
    </ButtonBar>
  );
};

export const ModalSubmitFooter: React.FC<ModalSubmitFooterProps> = ({
  message,
  errorMessage,
  inProgress,
  cancel,
  submitText,
  cancelText,
  className,
  submitDisabled,
  submitDanger,
  buttonAlignment = 'right',
  resetText,
  reset,
}) => {
  const { t } = useTranslation('plugin__pipelines-console-plugin');
  const onCancelClick = (e) => {
    e.stopPropagation();
    cancel(e);
  };

  const onResetClick = (e) => {
    e.stopPropagation();
    reset(e);
  };

  const cancelButton = (
    <Button
      type="button"
      variant="secondary"
      data-test-id="modal-cancel-action"
      onClick={onCancelClick}
      aria-label={t('Cancel')}
    >
      {cancelText || t('Cancel')}
    </Button>
  );

  const submitButton = (
    <Button
      data-test="confirm-action"
      id="confirm-action"
      isDisabled={submitDisabled}
      type="submit"
      variant={submitDanger ? 'danger' : 'primary'}
    >
      {submitText || t('Submit')}
    </Button>
  );

  const resetButton = (
    <Button variant="link" isInline onClick={onResetClick} id="reset-action">
      {resetText || t('Reset')}
    </Button>
  );

  return (
    <ModalFooter
      inProgress={inProgress}
      errorMessage={errorMessage}
      message={message}
      className={className}
    >
      <ActionGroup
        className={classNames(
          { 'pf-v6-c-form__actions--right': buttonAlignment === 'right' },
          'pf-v6-c-form  pf-v6-c-form__group--no-top-margin',
        )}
      >
        {buttonAlignment === 'left' ? (
          <>
            {submitButton}
            {reset && resetButton}
            {cancelButton}
          </>
        ) : (
          <>
            {reset && resetButton}
            {cancelButton}
            {submitButton}
          </>
        )}
      </ActionGroup>
    </ModalFooter>
  );
};

export const createModal: CreateModal = (getModalElement) => {
  const containerElement = document.getElementById('modal-container');
  const result = new Promise<void>((resolve) => {
    const closeModal = (e?: React.SyntheticEvent) => {
      if (e && e.stopPropagation) {
        e.stopPropagation();
      }
      ReactDOM.unmountComponentAtNode(containerElement);
      resolve();
    };
    containerElement &&
      ReactDOM.render(getModalElement(closeModal), containerElement);
  });
  return { result };
};

export const ModalWrapper: React.FC<ModalWrapperProps> = ({
  className,
  children,
  onClose,
}) => {
  return (
    <Modal
      className={classNames('modal-dialog', className)}
      isOpen
      onClose={() => onClose()}
    >
      {children}
    </Modal>
  );
};

export const createModalLauncher: CreateModalLauncher =
  (Component, modalWrapper = true) =>
  ({ blocking, modalClassName, close, cancel, ...props }) => {
    const getModalContainer: GetModalContainer = (onClose) => {
      const handleClose = (e: React.SyntheticEvent) => {
        onClose?.(e);
        close?.();
      };
      const handleCancel = (e: React.SyntheticEvent) => {
        cancel?.();
        handleClose(e);
      };

      return (
        <>
          {modalWrapper ? (
            <ModalWrapper
              blocking={blocking}
              className={modalClassName}
              onClose={handleClose}
            >
              <Component
                {...(props as any)}
                cancel={handleCancel}
                close={handleClose}
              />
            </ModalWrapper>
          ) : (
            <Component
              {...(props as any)}
              cancel={handleCancel}
              close={handleClose}
            />
          )}
        </>
      );
    };
    return createModal(getModalContainer);
  };

export type CreateModalLauncherProps = {
  blocking?: boolean;
  modalClassName?: string;
};

export type ModalWrapperProps = {
  blocking?: boolean;
  className?: string;
  onClose?: (event?: React.SyntheticEvent) => void;
};

export type GetModalContainer = (
  onClose: (e?: React.SyntheticEvent) => void,
) => React.ReactElement;

type CreateModal = (getModalContainer: GetModalContainer) => {
  result: Promise<any>;
};
export type ModalComponentProps = {
  cancel?: () => void;
  close?: () => void;
};

export type ModalTitleProps = {
  className?: string;
  close?: (e: React.SyntheticEvent<any, Event>) => void;
};

export type ModalBodyProps = {
  className?: string;
};

export type ModalFooterProps = {
  message?: string;
  errorMessage?: React.ReactNode;
  inProgress: boolean;
  className?: string;
};

export type ModalSubmitFooterProps = {
  message?: string;
  errorMessage?: string;
  inProgress: boolean;
  cancel: (e: React.SyntheticEvent<any, Event>) => void;
  cancelText?: React.ReactNode;
  className?: string;
  resetText?: React.ReactNode;
  reset?: (e: React.SyntheticEvent<any, Event>) => void;
  submitText: React.ReactNode;
  submitDisabled?: boolean;
  submitDanger?: boolean;
  buttonAlignment?: 'left' | 'right';
};

export type CreateModalLauncher = <P extends ModalComponentProps>(
  C: React.ComponentType<P>,
  modalWrapper?: boolean,
) => (props: P & CreateModalLauncherProps) => { result: Promise<{}> };
